function subarraySum(nums, k) {
  const sumCount = new Map();
  sumCount.set(0, 1);
  let currentSum = 0;
  let count = 0;

  for (const num of nums) {
    currentSum += num;

    // Check if (currentSum - k) exists
    if (sumCount.has(currentSum - k)) {
      count += sumCount.get(currentSum - k);
    }

    // Update frequency of current sum
    sumCount.set(currentSum, (sumCount.get(currentSum) || 0) + 1);
  }

  return count;
}

