function productExceptSelf(nums) {
  const n = nums.length;
  const result = new Array(n);

  // Compute left products
  result[0] = 1;
  for (let i = 1; i < n; i++) {
    result[i] = result[i-1] * nums[i-1];
  }

  // Compute right products and multiply
  let rightProduct = 1;
  for (let i = n - 1; i >= 0; i--) {
    result[i] *= rightProduct;
    rightProduct *= nums[i];
  }

  return result;
}

