function findMaxLength(nums) {
  const sumIndex = new Map();
  sumIndex.set(0, -1);
  let maxLen = 0;
  let sum = 0;

  for (let i = 0; i < nums.length; i++) {
    sum += nums[i] === 1 ? 1 : -1;

    if (sumIndex.has(sum)) {
      maxLen = Math.max(maxLen, i - sumIndex.get(sum));
    } else {
      sumIndex.set(sum, i);
    }
  }

  return maxLen;
}

