def find_max_length(nums):
    sum_index = {0: -1}
    max_len = 0
    current_sum = 0

    for i in range(len(nums)):
        current_sum += 1 if nums[i] == 1 else -1

        if current_sum in sum_index:
            max_len = max(max_len, i - sum_index[current_sum])
        else:
            sum_index[current_sum] = i

