class Solution {
    public int findMaxLength(int[] nums) {
        Map<Integer, Integer> sumIndex = new HashMap<>();
        sumIndex.put(0, -1);
        int maxLen = 0;
        int sum = 0;

        for (int i = 0; i < nums.length; i++) {
            sum += nums[i] == 1 ? 1 : -1;

            if (sumIndex.containsKey(sum)) {
                maxLen = Math.max(maxLen, i - sumIndex.get(sum));
            } else {
                sumIndex.put(sum, i);
            }
        }

        return maxLen;
    }
}

