int findMaxLength(int* nums, int numsSize) {
    // Simple O(n^2) solution for C
    int maxLen = 0;

    for (int i = 0; i < numsSize; i++) {
        int zeros = 0, ones = 0;
        for (int j = i; j < numsSize; j++) {
            if (nums[j] == 0) zeros++;
            else ones++;

            if (zeros == ones) {
                int len = j - i + 1;
                if (len > maxLen) maxLen = len;
            }
        }
    }

    return maxLen;
}
